export const AVAILABLE_ASSETS_BY_VIDEO = [...AVAILABLE_ASSETS, ...SCENE_SUPPLEMENTAL_ASSETS].reduce<Record<string, LibraryComponent[]>>((groups, asset) => {
  const key = asset.sourceVideo?.videoId ?? 'unknown'
  ;(groups[key] ??= []).push(asset)
  return groups
}, {})

export function assetsForVideoFrame(videoId: string, frameTime: number): LibraryComponent[] {
  return (AVAILABLE_ASSETS_BY_VIDEO[videoId] ?? []).flatMap((asset) => {
    const appearance = (asset.sourceVideo?.appearances ?? []).find((candidate) =>
      frameTime >= candidate.startSec && frameTime <= candidate.endSec
    )
    if (!appearance || !asset.sourceVideo) return []
    const minute = Math.floor(appearance.representativeSec / 60)
    const second = String(Math.floor(appearance.representativeSec % 60)).padStart(2, '0')
    const frameLabel = `${minute}:${second}`
    return [{
      ...asset,
      source: `${asset.sourceVideo.blogger} · ${videoId} · ${frameLabel}`,
      sourceVideo: {
        ...asset.sourceVideo,
        frameTime: frameLabel,
        startSec: appearance.startSec,
        endSec: appearance.endSec,
      },
    }]
  })
}

export function defaultAssetFrame(videoId: string): number {
  const times = (AVAILABLE_ASSETS_BY_VIDEO[videoId] ?? []).flatMap((asset) =>
    (asset.sourceVideo?.appearances ?? []).map((appearance) => appearance.representativeSec)
  )
  return times.length > 0 ? Math.min(...times) : 0
}
